    // 读取项目名称
    try {
      const result = await window.electronAPI.yaml.read(`${projectPath}/project.yaml`)
      if (result.success && result.data) {
        const data = result.data as Record<string, unknown>
        setProjectName(String(data.title || '小说'))
      }
    } catch {}
  }

  // 章节选择
  const handleChapterSelect = async (filePath: string) => {
    if (isDirty) {
      // 提示保存
      const userConfirmed = window.confirm('当前章节有未保存的内容，是否保存？')
      if (userConfirmed) await handleSave()
    }

    setChapterContent('')
    setActiveChapter(filePath)
    setIsDirty(false)

    // 读取章节内容
    try {
      const result = await window.electronAPI.readFile(filePath)
      if (result.success && result.content) {
        setChapterContent(result.content)
      }
    } catch (error) {
      message.error('读取章节失败')
    }
  }

  // 内容变化
  const handleContentChange = (value: string | undefined) => {
    if (value === undefined) return
    setChapterContent(value)
    setIsDirty(true)
  }

  // 快捷键保存
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault()
        handleSave()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [activeChapter, chapterContent, handleSave])

  return (
    <Layout style={{ height: '100vh' }}>
      {/* 顶部工具栏 */}
      <Layout.Header
        style={{
          display: 'flex',
          alignItems: 'center',
          padding: '0 20px',
          background: '#fff',
          borderBottom: '1px solid #e8e8e8',
          justifyContent: 'space-between'
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          <h2 style={{ margin: 0 }}>🍅 番茄小说创作助手</h2>
          {projectRoot && <span style={{ color: '#999' }}>当前项目：{projectRoot}</span>}
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <Button
            icon={<FolderOpenOutlined />}
            onClick={handleOpenProject}
          >
            打开项目
          </Button>
          <Button
            icon={<SaveOutlined />}
            type="primary"
            onClick={handleSave}
            disabled={saveStatus === 'saving' || !activeChapter}
            loading={saveStatus === 'saving'}
          >
            {saveStatus === 'saving'
              ? '保存中...'
              : saveStatus === 'saved'
                ? '已保存 ✓'
                : saveStatus === 'error'
                  ? '保存失败 ↺'
                  : isDirty
                    ? '保存 *'
                    : '已保存'}
          </Button>
          <Button
            icon={<BookOutlined />}
            onClick={() => setExportManagerVisible(true)}
            disabled={!projectRoot}
          >
            导出
          </Button>
        </div>
      </Layout.Header>

      <Layout>
        {/* 左侧边栏 */}
        <Sider width={64} theme="light">
          <Menu
            mode="inline"
            selectedKeys={[activeTab]}
            items={siderMenuItems}
            onClick={({ key }) => setActiveTab(key as TabKey)}
            style={{ height: '100%', borderRight: 0 }}
          />
        </Sider>

        {/* 左侧内容区 */}
        <Sider width={280} theme="light" style={{ borderRight: '1px solid #e8e8e8' }}>
          {activeTab === 'outline' && projectRoot && (
            <OutlineTree
              projectRoot={projectRoot}
              activeChapter={activeChapter}
              onSelect={handleChapterSelect}
            />
          )}
          {activeTab === 'characters' && projectRoot && (
            <CharactersPage
              projectRoot={projectRoot}
              onCharacterClick={(name) => {
                // 可选：切换到大纲并搜索该角色相关内容
              }}
            />
          )}
          {activeTab === 'world' && (
            <SettingsPage projectRoot={projectRoot} />
          )}
          {activeTab === 'facts' && <FactsPanel projectRoot={projectRoot} />}
          {activeTab === 'search' && (
            <VectorSearchPanel
              projectRoot={projectRoot}
              onJumpToChapter={(path) => {
                handleChapterSelect(path)
              }}
            />
          )}
          {activeTab === 'appSettings' && <AppSettingsPage />}
        </Sider>

        {/* 中间编辑区 */}
        <Content style={{ background: '#fff' }}>
          {activeChapter ? (
            <Editor
              ref={editorRef}
              value={chapterContent}
              onChange={handleContentChange}
              filePath={activeChapter}
            />
          ) : (
            <div
              style={{
                display: 'flex',
                height: '100%',
                alignItems: 'center',
                justifyContent: 'center',
                color: '#999',
                fontSize: 18,
              }}
            >
              请在左侧选择章节，或打开一个小说项目
            </div>
          )}
        </Content>

        {/* 右侧AI工具区 */}
        <Sider width={320} theme="light" style={{ borderLeft: '1px solid #e8e8e8' }}>
          <div style={{ display: 'flex', borderBottom: '1px solid #e8e8e8' }}>
            <Button
              type={rightPanelTab === 'ai' ? 'primary' : 'text'}
              size="small"
              style={{ flex: 1, borderRadius: 0 }}
              onClick={() => setRightPanelTab('ai')}
            >
              ✏️ AI工具
            </Button>
            <Button
              type={rightPanelTab === 'analysis' ? 'primary' : 'text'}
              size="small"
              style={{ flex: 1, borderRadius: 0 }}
              onClick={() => setRightPanelTab('analysis')}
            >
              📊 分析
            </Button>
          </div>
          {rightPanelTab === 'ai' ? (
            <AIToolsPanel
              chapterContent={chapterContent}
              chapterPath={activeChapter}
              getSelectedText={() => editorRef.current?.getSelectedText() || ''}
              onInsertText={(text) => {
                if (text.startsWith('__REPLACE__')) {
                  const newContent = text.slice('__REPLACE__'.length)
                  setChapterContent(newContent)
                } else {
                  setChapterContent(prev => prev + text)
                }
                setIsDirty(true)
              }}
            />
          ) : (
            <AnalysisPanel
              chapterContent={chapterContent}
              chapterPath={activeChapter}
              projectRoot={projectRoot}
            />
          )}
        </Sider>
      </Layout>

      {/* 项目管理对话框 */}
      <ProjectManager
        visible={projectManagerVisible}
        onClose={() => setProjectManagerVisible(false)}
        onProjectOpened={handleProjectOpened}
      />
      <ExportManager
        visible={exportManagerVisible}
        projectRoot={projectRoot}
        projectName={projectName}
        onClose={() => setExportManagerVisible(false)}
      />
    </Layout>
  )
}

export default Workbench

/**
 * 角色详情编辑页面
 * 支持新建和编辑角色，保存为 YAML 文件
 */

import { useState, useEffect } from 'react'
import {
  Modal,
  Form,
  Input,
  Select,
  Button,
  Space,
  Card,
  Divider,
  message,
  Row,
  Col,
  Switch,
  Tooltip,
} from 'antd'
import {
  SaveOutlined,
  PlusOutlined,
  DeleteOutlined,
  ThunderboltOutlined,
} from '@ant-design/icons'

const { TextArea } = Input

interface RelationshipItem {
  key: string
  target: string
  type: string
  strength: number
}

interface CharacterDetailProps {
  visible: boolean
  character: {
    id: string
    name: string
    filePath: string
    mbti?: string
    appearance?: string
    ability?: string
    goal?: string
    flaw?: string
    background?: string
    notes?: string
  } | null
  projectRoot: string | null
  onClose: () => void
  onSaved: () => void
}

const MBTI_OPTIONS = [
  'INTJ', 'INTP', 'ENTJ', 'ENTP',
  'INFJ', 'INFP', 'ENFJ', 'ENFP',
  'ISTJ', 'ISFJ', 'ESTJ', 'ESFJ',
  'ISTP', 'ISFP', 'ESTP', 'ESFP',
]

const RELATION_TYPES = [
  { value: 'mentor', label: '师徒' },
  { value: 'rival', label: '对手/敌对' },
  { value: 'love', label: '爱恋' },
  { value: 'family', label: '家族' },
  { value: 'friend', label: '朋友/盟友' },
  { value: 'master', label: '师承' },
  { value: 'enemy', label: '仇敌' },
]

const CharacterDetail: React.FC<CharacterDetailProps> = ({
  visible,
  character,
  projectRoot,
  onClose,
  onSaved,
}) => {
  const [form] = Form.useForm()
  const [saving, setSaving] = useState(false)
  const [relationships, setRelationships] = useState<RelationshipItem[]>([])

  // 填充表单
  useEffect(() => {
    if (visible && character) {
      form.setFieldsValue({
        name: character.name,
        mbti: character.mbti,
        appearance: character.appearance,
        ability: character.ability,
        goal: character.goal,
        flaw: character.flaw,
        background: character.background,
        notes: character.notes,
      })
    } else if (visible) {
      form.resetFields()
    }
  }, [visible, character, form])

  // 加载关系数据（带竞态保护：快速切换角色时取消旧请求）
  useEffect(() => {
    let cancelled = false
    if (visible && character && projectRoot) {
      loadRelationships(cancelled)
    }
    return () => { cancelled = true }
  }, [visible, character, projectRoot])

  const loadRelationships = async (cancelled: boolean) => {
    if (!projectRoot) return
    try {
      const relFile = `${projectRoot}/relationships.yaml`
      const result = await window.electronAPI.yaml.read(relFile)
      if (cancelled) return
      if (result.success && result.data) {
        const relData = result.data as { relationships?: Array<{ from: string; to: string; type: string; strength: number }> }
        const rels = (relData.relationships || []).filter(
          r => r.from === character?.name || r.to === character?.name
        )
        setRelationships(
          rels.map((r, idx) => ({
            key: `${idx}`,
            target: r.from === character?.name ? r.to : r.from,
            type: r.type,
            strength: r.strength,
          }))
        )
      }
    } catch (error) {
      console.error('加载关系失败:', error)
      message.error('加载人物关系失败，请检查关系文件')
    }
  }

  // 添加关系
  const handleAddRelationship = () => {
    setRelationships(prev => [
      ...prev,
      { key: Date.now().toString(), target: '', type: 'friend', strength: 0.5 },
    ])
  }

  // 删除关系
  const handleRemoveRelationship = (key: string) => {
    setRelationships(prev => prev.filter(r => r.key !== key))
  }

  // 保存角色
  const handleSave = async () => {
    try {
      const values = await form.validateFields()

      if (!values.name) {
        message.error('请输入角色名称')
        return
      }

      if (!projectRoot) {
        message.error('未设置项目根路径')
        return
      }

      setSaving(true)

      // 构建角色数据
      const charData: Record<string, unknown> = {
        name: values.name,
        mbti: values.mbti,
        key_attributes: {
          appearance: values.appearance,
          ability: values.ability,
          goal: values.goal,
          flaw: values.flaw,
        },
        background: values.background,
        notes: values.notes,
      }

      // 确定文件路径
      const safeName = values.name.replace(/[/\\?%*:|"<>]/g, '_')
      const filePath = `${projectRoot}/characters/${safeName}.yaml`

      const result = await window.electronAPI.yaml.write(filePath, charData)
      if (!result.success) {
        message.error(`保存失败: ${result.error}`)
        setSaving(false)
        return
      }

      // 更新关系文件（单次读写：改名引用 + 移除旧关系 + 追加新关系合并为一次写回）
      if (values.name) {
        const relFile = `${projectRoot}/relationships.yaml`
        const relResult = await window.electronAPI.yaml.read(relFile)
        const relData = (relResult.success && relResult.data) as {
          relationships?: Array<{
            from: string; to: string; type: string; strength: number; development?: unknown[]
          }>
        } || { relationships: [] }
        const rels = relData.relationships || []

        // 1. 若角色改名，同时更新关系中的旧引用
        if (character?.name && character.name !== values.name) {
          for (const r of rels) {
            if (r.from === character.name) r.from = values.name
            if (r.to === character.name) r.to = values.name
          }
        }

        // 2. 移除该角色的旧关系
        const nameToUse = character?.name || values.name
        const filteredRels = rels.filter(r => r.from !== nameToUse && r.to !== nameToUse)

        // 3. 追加新关系
        const finalRels = relationships
          .filter(r => r.target && r.type)
          .map(r => ({
            from: nameToUse,
            to: r.target,
            type: r.type,
            strength: r.strength,
            development: [{ chapter: 1, event: '初遇', strength: r.strength }],
          }))

        relData.relationships = [...filteredRels, ...finalRels]
        const relWriteResult = await window.electronAPI.yaml.write(relFile, relData)
        if (!relWriteResult.success) {
          message.error(`关系保存失败: ${relWriteResult.error}`)
          setSaving(false)
          return
        }
      }

      message.success('角色已保存')
      onSaved()
    } catch (error) {
      console.error('保存角色失败:', error)
      message.error('保存失败')
    } finally {
      setSaving(false)
    }
  }

  return (
    <Modal
      title={character ? `编辑角色：${character.name}` : '新建角色'}
      open={visible}
      onCancel={onClose}
      width={800}
      footer={
        <Space>
          <Button onClick={onClose}>取消</Button>
          <Button
            type="primary"
            icon={<SaveOutlined />}
            loading={saving}
            onClick={handleSave}
          >
            保存
          </Button>
        </Space>
      }
    >
      <Form
        form={form}
        layout="vertical"
        style={{ maxHeight: '70vh', overflow: 'auto' }}
      >
        <Row gutter={16}>
          <Col span={12}>
            <Form.Item
              name="name"
              label="角色名称"
              rules={[{ required: true, message: '请输入角色名称' }]}
            >
              <Input placeholder="如：林枫" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item name="mbti" label="MBTI">
              <Select
                placeholder="选择人格类型"
                options={MBTI_OPTIONS.map(m => ({ value: m, label: m }))}
                allowClear
              />
            </Form.Item>
          </Col>
        </Row>

        <Divider>
          <ThunderboltOutlined /> 核心属性
        </Divider>

        <Form.Item name="ability" label="能力/特长">
          <Input placeholder="如：剑术天才，重生后拥有前世记忆" />
        </Form.Item>

        <Form.Item name="goal" label="核心目标">
          <Input placeholder="如：推翻血魔宗，拯救修真界" />
        </Form.Item>

        <Form.Item name="flaw" label="核心缺陷/弱点">
          <Input placeholder="如：过于理性，不善表达情感" />
        </Form.Item>

        <Form.Item name="appearance" label="外貌特征">
          <TextArea
            placeholder="如：黑色长发，冷峻面容，眼神锐利"
            rows={2}
          />
        </Form.Item>

        <Divider>背景故事</Divider>

        <Form.Item name="background" label="背景">
          <TextArea
            placeholder="角色背景故事..."
            rows={4}
          />
        </Form.Item>

        <Form.Item name="notes" label="创作笔记">
          <TextArea
            placeholder="如：后期需要设计一个情感突破口..."
            rows={3}
          />
        </Form.Item>

        <Divider>人物关系</Divider>

        <div style={{ marginBottom: 12 }}>
          <Button
            type="dashed"
            icon={<PlusOutlined />}
            onClick={handleAddRelationship}
            block
          >
            添加关系
          </Button>
        </div>

        {relationships.map((rel, idx) => (
          <Card
            key={rel.key}
            size="small"
            style={{ marginBottom: 8 }}
          >
            <Row gutter={12} align="middle">
              <Col span={8}>
                <Input
                  placeholder="对方角色名"
                  value={rel.target}
                  onChange={(e) => {
                    const updated = [...relationships]
                    updated[idx].target = e.target.value
                    setRelationships(updated)
                  }}
                />
              </Col>
              <Col span={6}>
                <Select
                  value={rel.type}
                  onChange={(val) => {
                    const updated = [...relationships]
                    updated[idx].type = val
                    setRelationships(updated)
                  }}
                  options={RELATION_TYPES}
                  style={{ width: '100%' }}
                />
              </Col>
              <Col span={6}>
                <Input
                  type="number"
                  min={0}
                  max={1}
                  step={0.1}
                  placeholder="强度 0-1"
                  value={rel.strength}
                  onChange={(e) => {
                    const updated = [...relationships]
                    updated[idx].strength = parseFloat(e.target.value) || 0
                    setRelationships(updated)
                  }}
                />
              </Col>
              <Col span={4}>
                <Button
                  type="text"
                  danger
                  icon={<DeleteOutlined />}
                  onClick={() => handleRemoveRelationship(rel.key)}
                />
              </Col>
            </Row>
          </Card>
        ))}

        {relationships.length === 0 && (
          <div style={{ color: '#999', textAlign: 'center', padding: 16 }}>
            暂无关系，点击上方按钮添加
          </div>
        )}
      </Form>
    </Modal>
  )
}

export default CharacterDetail

/**
 * 应用设置页面
 * API密钥管理、模型选择、温度参数、主题切换、自动保存间隔
 */

import { useState, useEffect } from 'react'
import {
  Card,
  Form,
  Input,
  Select,
  Slider,
  Switch,
  Button,
  Space,
  Divider,
  message,
  Alert,
  Tabs,
  Tag,
  Tooltip,
  InputNumber,
  List,
  Modal,
} from 'antd'
import {
  KeyOutlined,
  SaveOutlined,
  CheckCircleOutlined,
  CloseCircleOutlined,
  ApiOutlined,
  SettingOutlined,
  ExperimentOutlined,
} from '@ant-design/icons'

// 可用的 AI 服务
const AI_SERVICES = [
  { value: 'deepseek', label: 'DeepSeek', models: ['deepseek-chat', 'deepseek-reasoner'] },
  { value: 'doubao', label: '豆包 (Doubao)', models: ['doubao-pro', 'doubao-lite', 'doubao-mini'] },
]

// 主题选项
const THEME_OPTIONS = [
  { value: 'light', label: '浅色' },
  { value: 'dark', label: '深色' },
  { value: 'system', label: '跟随系统' },
]

interface AppSettings {
  // AI 设置
  aiServices: Record<string, { apiKey: string; model: string; temperature: number; enabled: boolean }>
  // 自动保存
  autoSaveInterval: number // 秒
  autoSaveEnabled: boolean
  // 外观
  theme: string
  editorFontSize: number
  editorLineHeight: number
}

const DEFAULT_SETTINGS: AppSettings = {
  aiServices: {
    deepseek: { apiKey: '', model: 'deepseek-chat', temperature: 0.7, enabled: true },
    doubao: { apiKey: '', model: 'doubao-pro', temperature: 0.8, enabled: false },
  },
  autoSaveInterval: 5,
  autoSaveEnabled: true,
  theme: 'light',
  editorFontSize: 16,
  editorLineHeight: 1.8,
}

const AppSettingsPage: React.FC = () => {
  const [form] = Form.useForm<AppSettings>()
  const [saving, setSaving] = useState(false)
  const [testingService, setTestingService] = useState<string | null>(null)
  const [testResult, setTestResult] = useState<Record<string, boolean>>({})

  // 加载设置
  const loadSettings = async () => {
    try {
      const result = await window.electronAPI.ai.getSetting('appSettings', DEFAULT_SETTINGS)
      if (result.success && result.value) {
        form.setFieldsValue(result.value as AppSettings)
      } else {
        form.setFieldsValue(DEFAULT_SETTINGS)
      }
    } catch (error) {
      form.setFieldsValue(DEFAULT_SETTINGS)
    }
  }

  useEffect(() => {
    loadSettings()
  }, [])

  // 保存设置
  const handleSave = async () => {
    try {
      const values = form.getFieldsValue()
      setSaving(true)

      // 检查是否有 API key 需要加密保存
      for (const [service, config] of Object.entries(values.aiServices || {})) {
        if (config.apiKey && !config.apiKey.startsWith('encrypted:')) {
          // 加密保存
          try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const encFn = window.electronAPI.safeStorage.encrypt as (text: string) => Promise<{ success: boolean; data?: Uint8Array; error?: string }>
            const encResult = await encFn(config.apiKey)
            if (encResult.success && encResult.data) {
              // 将 Uint8Array 转为 base64 字符串存储
              const base64 = btoa(String.fromCharCode(...encResult.data))
              values.aiServices[service].apiKey = `encrypted:${base64}`
            }
          } catch (e) {
            console.warn('API key 加密失败，将以明文保存（不推荐）:', e)
            message.warning('API key 加密失败，已以明文保存（请注意安全）')
          }
        }
      }

      await window.electronAPI.ai.saveSetting('appSettings', values)
      message.success('设置已保存')
    } catch (error) {
      message.error('保存失败')
    } finally {
      setSaving(false)
    }
  }

  // 测试连接
  const handleTestConnection = async (service: string) => {
    setTestingService(service)
    setTestResult(prev => ({ ...prev, [service]: false }))
    try {
      const result = await window.electronAPI.ai.testConnection(service)
      setTestResult(prev => ({ ...prev, [service]: !!(result.success && result.result) }))
      if (result.success && result.result) {
        message.success(`${service} 连接成功`)
      } else {
        message.error(`${service} 连接失败: ${result.error || '未知错误'}`)
      }
    } catch (error) {
      setTestResult(prev => ({ ...prev, [service]: false }))
      message.error(`${service} 连接失败`)
    } finally {
      setTestingService(null)
    }
  }

  // 验证 API Key 格式（解密显示）
  const getDisplayApiKey = (apiKey: string) => {
    if (!apiKey) return ''
    if (apiKey.startsWith('encrypted:')) {
      return '••••••••（已加密）'
    }
    if (apiKey.length > 8) {
      return apiKey.slice(0, 4) + '••••••••' + apiKey.slice(-4)
    }
    return apiKey
  }

  const values = form.getFieldsValue()

  return (
    <div
      style={{
        maxWidth: 800,
        margin: '0 auto',
        padding: 24,
        overflow: 'auto',
        height: '100%',
      }}
    >
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: 24,
        }}
      >
        <h2 style={{ margin: 0 }}>⚙️ 应用设置</h2>
        <Button
          type="primary"
          icon={<SaveOutlined />}
          loading={saving}
          onClick={handleSave}
        >
          保存设置
        </Button>
      </div>

      <Form
        form={form}
        layout="vertical"
        initialValues={DEFAULT_SETTINGS}
      >
        <Tabs
          items={[
            {
              key: 'ai',
              label: <span><ApiOutlined /> AI 服务</span>,
              children: (
                <div>
                  {AI_SERVICES.map(service => (
                    <Card
                      key={service.value}
                      size="small"
                      title={
                        <Space>
                          {service.label}
                          <Tag color={values.aiServices?.[service.value]?.enabled ? 'green' : 'default'}>
                            {values.aiServices?.[service.value]?.enabled ? '已启用' : '未启用'}
                          </Tag>
                        </Space>
                      }
                      style={{ marginBottom: 16 }}
                      extra={
                        <Switch
                          checked={values.aiServices?.[service.value]?.enabled}
                          onChange={(checked) => {
                            const current = form.getFieldValue(['aiServices', service.value]) || {}
                            form.setFieldsValue({
                              aiServices: {
                                [service.value]: { ...current, enabled: checked },
                              },
                            })
                          }}
                        />
                      }
                    >
                      <Form.Item
                        label="API Key"
                        name={['aiServices', service.value, 'apiKey']}
                        extra={
                          values.aiServices?.[service.value]?.apiKey && (
                            <Tag style={{ marginTop: 4 }}>
                              {getDisplayApiKey(values.aiServices?.[service.value]?.apiKey || '')}
                            </Tag>
                          )
                        }
                      >
                        <Input.Password
                          placeholder={
                            service.value === 'deepseek'
                              ? 'sk-xxxxxxxxxxxxxxxx'
                              : '输入 API Key'
                          }
                        />
                      </Form.Item>

                      <Form.Item
                        label="模型"
                        name={['aiServices', service.value, 'model']}
                      >
                        <Select
                          options={service.models.map(m => ({ value: m, label: m }))}
                          style={{ width: 200 }}
                        />
                      </Form.Item>

                      <Form.Item
                        label={
                          <Tooltip title="Temperature 控制创造性：0.0-0.3 更确定性，0.7-1.0 更有创意">
                            Temperature（创造性）
                          </Tooltip>
                        }
                        name={['aiServices', service.value, 'temperature']}
                      >
                        <Slider
                          min={0}
                          max={1}
                          step={0.1}
                          marks={{
                            0: '精准',
                            0.5: '平衡',
                            1: '创意',
                          }}
                          style={{ width: 300 }}
                        />
                      </Form.Item>

                      <Button
                        size="small"
                        icon={
                          testResult[service.value] ? (
                            <CheckCircleOutlined style={{ color: '#52c41a' }} />
                          ) : testResult[service.value] === false ? (
                            <CloseCircleOutlined style={{ color: '#ff4d4f' }} />
                          ) : undefined
                        }
                        onClick={() => handleTestConnection(service.value)}
                        loading={testingService === service.value}
                      >
                        测试连接
                      </Button>
                    </Card>
                  ))}

                  <Alert
                    message="API Key 安全说明"
                    description="API Key 将使用系统安全存储（SafeStorage）加密保存，不会以明文形式存储在配置文件中。"
                    type="info"
                    showIcon
                  />
                </div>
              ),
            },
            {
              key: 'editor',
              label: <span><ExperimentOutlined /> 编辑器</span>,
              children: (
                <div>
                  <Card size="small" title="自动保存" style={{ marginBottom: 16 }}>
                    <Form.Item
                      label="启用自动保存"
                      name="autoSaveEnabled"
                      valuePropName="checked"
                    >
                      <Switch />
                    </Form.Item>

                    <Form.Item
                      label="自动保存间隔（秒）"
                      name="autoSaveInterval"
                    >
                      <Slider
                        min={1}
                        max={30}
                        marks={{ 3: '3秒', 5: '5秒', 10: '10秒', 30: '30秒' }}
                        disabled={!values.autoSaveEnabled}
                      />
                    </Form.Item>
                  </Card>

                  <Card size="small" title="编辑器外观">
                    <Form.Item
                      label="字体大小"
                      name="editorFontSize"
                    >
                      <Slider
                        min={12}
                        max={24}
                        marks={{ 14: '14', 16: '16', 18: '18', 20: '20' }}
                      />
                    </Form.Item>

                    <Form.Item
                      label="行高"
                      name="editorLineHeight"
                    >
                      <Slider
                        min={1.2}
                        max={2.5}
                        step={0.1}
                        marks={{ 1.6: '1.6', 1.8: '1.8', 2.0: '2.0' }}
                      />
                    </Form.Item>
                  </Card>
                </div>
              ),
            },
            {
              key: 'appearance',
              label: <span><SettingOutlined /> 外观</span>,
              children: (
                <Card size="small" title="主题设置">
                  <Form.Item
                    label="主题"
                    name="theme"
                  >
                    <Select options={THEME_OPTIONS} style={{ width: 200 }} />
                  </Form.Item>

                  <Alert
                    message="深色主题切换需要重启应用生效"
                    type="warning"
                    showIcon
                    style={{ marginTop: 8 }}
                  />
                </Card>
              ),
            },
          ]}
        />
      </Form>
    </div>
  )
}

export default AppSettingsPage
